@SpringBootApplication
public class OidcClientApplication {
    public static void main(String[] args) {
        SpringApplication.run(OidcClientApplication.class, args);
    }
}

@Configuration
class OidcClientConfig {

    @Bean
    public ClientRegistrationRepository clientRegistrationRepository() {
        return new InMemoryClientRegistrationRepository(oidcClientRegistration());
    }

    @Bean
    public OAuth2AuthorizedClientService authorizedClientService(ClientRegistrationRepository repo) {
        return new InMemoryOAuth2AuthorizedClientService(repo);
    }

    @Bean
    public OAuth2AuthorizedClientRepository authorizedClientRepository(OAuth2AuthorizedClientService service) {
        return new AuthenticatedPrincipalOAuth2AuthorizedClientRepository(service);
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.disable())
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/", "/public/**", "/login/**", "/oauth2/**", "/error").permitAll()
                .anyRequest().authenticated()
            )
            .oauth2Login(oauth2 -> oauth2
                .loginPage("/login")
                .userInfoEndpoint(userInfo -> userInfo.oidcUserService(oidcUserService()))
            )
            .logout(logout -> logout.logoutSuccessUrl("/"));
        return http.build();
    }

    @Bean
    public OidcUserService oidcUserService() {
        return new CustomOidcUserService();
    }

    @Bean
    public OidcSessionManager oidcSessionManager() {
        return new OidcSessionManager();
    }

    @Bean
    public ObjectMapper objectMapper() {
        return new ObjectMapper();
    }

    @Bean
    public RestClient restClient() {
        return RestClient.create();
    }

    private ClientRegistration oidcClientRegistration() {
        String issuer = "https://provider.example.com";
        String authorizationUri = issuer + "/oauth2/authorize";
        String tokenUri = issuer + "/oauth2/token";
        String userInfoUri = issuer + "/oauth2/userinfo";
        String jwkSetUri = issuer + "/oauth2/jwks";

        return ClientRegistration.withRegistrationId("oidc")
            .clientId("your-client-id")
            .clientSecret("your-client-secret")
            .scope("openid", "profile", "email")
            .authorizationGrantType(org.springframework.security.oauth2.core.AuthorizationGrantType.AUTHORIZATION_CODE)
            .redirectUri("{baseUrl}/login/oauth2/code/{registrationId}")
            .authorizationUri(authorizationUri)
            .tokenUri(tokenUri)
            .userInfoUri(userInfoUri)
            .jwkSetUri(jwkSetUri)
            .userNameAttributeName(IdTokenClaimNames.SUB)
            .clientName("OIDC")
            .issuerUri(issuer)
            .build();
    }
}

class CustomOidcUserService extends OidcUserService {
    private final ObjectMapper objectMapper = new ObjectMapper();
    private final RestClient restClient = RestClient.create();

    @Override
    public org.springframework.security.oauth2.core.oidc.user.OidcUser loadUser(OidcUserRequest userRequest) {
        OidcIdToken idToken = userRequest.getIdToken();
        Map<String, Object> claims = new HashMap<>(idToken.getClaims());

        OidcUserInfo userInfo = fetchUserInfo(userRequest.getAccessToken().getTokenValue(), userRequest.getClientRegistration().getProviderDetails().getUserInfoEndpoint().getUri());
        if (userInfo != null) {
            claims.putAll(userInfo.getClaims());
        }

        Collection<GrantedAuthority> authorities = Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER"));
        return new DefaultOidcUser(authorities, idToken, userInfo, IdTokenClaimNames.SUB);
    }

    private OidcUserInfo fetchUserInfo(String accessToken, String userInfoUri) {
        if (userInfoUri == null || userInfoUri.isBlank()) {
            return null;
        }
        try {
            ResponseEntity<String> response = restClient.get()
                .uri(userInfoUri)
                .header("Authorization", "Bearer " + accessToken)
                .retrieve()
                .toEntity(String.class);

            if (!response.getStatusCode().is2xxSuccessful() || response.getBody() == null) {
                return null;
            }

            Map<String, Object> claims = objectMapper.readValue(response.getBody(), new TypeReference<Map<String, Object>>() {});
            return new OidcUserInfo(claims);
        } catch (Exception e) {
            return null;
        }
    }
}

@RestController
class WebController {
    private final OidcSessionManager sessionManager;

    WebController(OidcSessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @GetMapping("/")
    public String home(HttpServletRequest request) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication == null || !authentication.isAuthenticated() || authentication.getPrincipal() == null) {
            return "Welcome. Please go to /login";
        }
        return "Authenticated as: " + authentication.getName();
    }

    @GetMapping("/login")
    public ResponseEntity<Void> login(HttpServletRequest request) {
        return ResponseEntity.status(HttpStatus.FOUND)
            .header("Location", "/oauth2/authorization/oidc")
            .build();
    }

    @GetMapping("/me")
    public Map<String, Object> me(Authentication authentication, HttpServletRequest request) {
        if (authentication == null) {
            throw new AuthenticationCredentialsNotFoundException("Not authenticated");
        }
        return sessionManager.currentSession(authentication, request);
    }
}

class OidcSessionManager {
    private final ObjectMapper objectMapper = new ObjectMapper();

    public Map<String, Object> currentSession(Authentication authentication, HttpServletRequest request) {
        Map<String, Object> session = new LinkedHashMap<>();
        session.put("authenticated", authentication != null && authentication.isAuthenticated());
        session.put("principal", authentication != null ? authentication.getName() : null);

        if (authentication != null && authentication.getPrincipal() instanceof DefaultOidcUser oidcUser) {
            session.put("claims", oidcUser.getClaims());
        }
        HttpSession httpSession = request.getSession(false);
        session.put("sessionId", httpSession != null ? httpSession.getId() : null);
        session.put("issuedAt", Instant.now().toString());
        return session;
    }

    public Map<String, Object> parseIdTokenClaims(String idToken) {
        if (idToken == null || idToken.isBlank()) {
            return Collections.emptyMap();
        }
        String[] parts = idToken.split("\\.");
        if (parts.length < 2) {
            return Collections.emptyMap();
        }
        try {
            String payload = new String(Base64.getUrlDecoder().decode(parts[1]), StandardCharsets.UTF_8);
            return objectMapper.readValue(payload, new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            return Collections.emptyMap();
        }
    }
}